/*
* Required Other Navigation Limits (Required-> YES, No required-> NO)
* by Ana Castillo
*/
//It is submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    //Other Navigation Limits
    if (this.YQP_NAVIGATION_LIMITS == "Other") {
        return "YES";
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Validate Gross Broken amount to show or hide (Show -> YES, Hide -> NO)
* by Ana Castillo
*/
//It is submit
if (this.YQP_SUBMIT_SAVE == "SUBMIT") {
    if (this.YQP_GROSS_BROKER_CHANGE) {
        return "YES";
    } else {
        return "NO";
    }
} else {
    return "NO";
}

/*
* Calc Broker Total Premium value
* by Ana Castillo
*/
//If the check is selected
if (this.YQP_GROSS_BROKER_CHANGE && 
    this.YQP_BROKER_PERCENTAGE != "" && 
    this.YQP_BROKER_PERCENTAGE != null) {
    let percentage = this.YQP_BROKER_PERCENTAGE;
    percentage = percentage / 100;
    //Rest percentage to the 100%
    let percentageTotal =  1 - percentage;
    let grossWritten = this.YQP_TOTAL_PREMIUM;
    //Add the percentage to the new total
    let brokerTotal = (grossWritten / percentageTotal);
    return brokerTotal;
} else {
    return "0";
}

/*
* Calc Get the user id of the request 
* by Helen Callisaya
*/
return this._user.id;

/*
* Calc Get the user fullname of the request 
* by Helen Callisaya
*/
return this._user.fullname;

/*
* Show request error
* by Helen Callisaya
*/
//validates if the FORTE_ERRORS.FORTE_ERROR_LOG variable has no errors
if (this.FORTE_ERRORS.FORTE_ERROR_LOG == "" || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == "no-error" || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == null || 
    this.FORTE_ERRORS.FORTE_ERROR_LOG == undefined) {
    return false;
} else {
    return true;
}

